#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long h = (long long)((sqrt(8.0 * N + 1) - 1) / 2);
        printf("%lld\n", h);
    }
    return 0;
}

